-- Supabase PostgreSQL DDL for Food Delivery Platform
-- Generated for project-a29e0eec

-- Enable UUID extension
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

-- Users table
CREATE TABLE IF NOT EXISTS public.users (
  id uuid PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE,
  name text,
  email text UNIQUE,
  phone text,
  avatar text,
  "defaultAddressId" text,
  "walletBalance" numeric DEFAULT 0,
  "referralCode" text,
  created_at timestamptz DEFAULT now(),
  updated_at timestamptz DEFAULT now()
);

ALTER TABLE public.users ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can view own profile" ON public.users
  FOR SELECT USING (auth.uid() = id);

CREATE POLICY "Users can update own profile" ON public.users
  FOR UPDATE USING (auth.uid() = id);

CREATE INDEX IF NOT EXISTS idx_users_email ON public.users(email);
CREATE INDEX IF NOT EXISTS idx_users_referral_code ON public.users("referralCode");

-- Addresses table
CREATE TABLE IF NOT EXISTS public.addresses (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "userId" uuid NOT NULL REFERENCES public.users(id) ON DELETE CASCADE,
  label text,
  street text,
  city text,
  "zipCode" text,
  latitude numeric,
  longitude numeric,
  "isDefault" boolean DEFAULT false,
  created_at timestamptz DEFAULT now(),
  updated_at timestamptz DEFAULT now()
);

ALTER TABLE public.addresses ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can view own addresses" ON public.addresses
  FOR SELECT USING (auth.uid() = "userId");

CREATE POLICY "Users can insert own addresses" ON public.addresses
  FOR INSERT WITH CHECK (auth.uid() = "userId");

CREATE POLICY "Users can update own addresses" ON public.addresses
  FOR UPDATE USING (auth.uid() = "userId");

CREATE POLICY "Users can delete own addresses" ON public.addresses
  FOR DELETE USING (auth.uid() = "userId");

CREATE INDEX IF NOT EXISTS idx_addresses_user_id ON public.addresses("userId");
CREATE INDEX IF NOT EXISTS idx_addresses_is_default ON public.addresses("isDefault");

-- Payment Methods table
CREATE TABLE IF NOT EXISTS public."paymentMethods" (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "userId" uuid NOT NULL REFERENCES public.users(id) ON DELETE CASCADE,
  type text,
  "cardLast4" text,
  "cardBrand" text,
  "cardExpiry" text,
  "isDefault" boolean DEFAULT false,
  created_at timestamptz DEFAULT now(),
  updated_at timestamptz DEFAULT now()
);

ALTER TABLE public."paymentMethods" ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can view own payment methods" ON public."paymentMethods"
  FOR SELECT USING (auth.uid() = "userId");

CREATE POLICY "Users can insert own payment methods" ON public."paymentMethods"
  FOR INSERT WITH CHECK (auth.uid() = "userId");

CREATE POLICY "Users can update own payment methods" ON public."paymentMethods"
  FOR UPDATE USING (auth.uid() = "userId");

CREATE POLICY "Users can delete own payment methods" ON public."paymentMethods"
  FOR DELETE USING (auth.uid() = "userId");

CREATE INDEX IF NOT EXISTS idx_payment_methods_user_id ON public."paymentMethods"("userId");

-- Restaurants table
CREATE TABLE IF NOT EXISTS public.restaurants (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  name text NOT NULL,
  cuisine text[],
  rating numeric,
  "reviewCount" integer DEFAULT 0,
  "deliveryTime" text,
  "deliveryFee" numeric,
  "minOrder" numeric,
  "isOpen" boolean DEFAULT true,
  "imageUrl" text,
  address text,
  latitude numeric,
  longitude numeric,
  distance text,
  "priceRange" text,
  created_at timestamptz DEFAULT now(),
  updated_at timestamptz DEFAULT now()
);

ALTER TABLE public.restaurants ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Anyone can view restaurants" ON public.restaurants
  FOR SELECT USING (true);

CREATE INDEX IF NOT EXISTS idx_restaurants_name ON public.restaurants(name);
CREATE INDEX IF NOT EXISTS idx_restaurants_is_open ON public.restaurants("isOpen");
CREATE INDEX IF NOT EXISTS idx_restaurants_rating ON public.restaurants(rating DESC);

-- Menu Items table
CREATE TABLE IF NOT EXISTS public."menuItems" (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "restaurantId" uuid NOT NULL REFERENCES public.restaurants(id) ON DELETE CASCADE,
  name text NOT NULL,
  description text,
  price numeric NOT NULL,
  "imageUrl" text,
  category text,
  "isVegetarian" boolean DEFAULT false,
  "isVegan" boolean DEFAULT false,
  "isGlutenFree" boolean DEFAULT false,
  "isAvailable" boolean DEFAULT true,
  calories integer,
  created_at timestamptz DEFAULT now(),
  updated_at timestamptz DEFAULT now()
);

ALTER TABLE public."menuItems" ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Anyone can view menu items" ON public."menuItems"
  FOR SELECT USING (true);

CREATE INDEX IF NOT EXISTS idx_menu_items_restaurant_id ON public."menuItems"("restaurantId");
CREATE INDEX IF NOT EXISTS idx_menu_items_category ON public."menuItems"(category);
CREATE INDEX IF NOT EXISTS idx_menu_items_is_available ON public."menuItems"("isAvailable");

-- Orders table
CREATE TABLE IF NOT EXISTS public.orders (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "userId" uuid NOT NULL REFERENCES public.users(id) ON DELETE CASCADE,
  "restaurantId" uuid NOT NULL REFERENCES public.restaurants(id) ON DELETE RESTRICT,
  "totalPrice" numeric NOT NULL,
  subtotal numeric,
  tax numeric,
  "deliveryFee" numeric,
  discount numeric DEFAULT 0,
  "promoCode" text,
  status text DEFAULT 'pending',
  "deliveryAddressId" uuid REFERENCES public.addresses(id) ON DELETE SET NULL,
  "paymentMethodId" uuid REFERENCES public."paymentMethods"(id) ON DELETE SET NULL,
  "estimatedDeliveryTime" timestamptz,
  "actualDeliveryTime" timestamptz,
  "deliveryPartnerId" uuid,
  rating integer,
  review text,
  created_at timestamptz DEFAULT now(),
  updated_at timestamptz DEFAULT now()
);

ALTER TABLE public.orders ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can view own orders" ON public.orders
  FOR SELECT USING (auth.uid() = "userId");

CREATE POLICY "Users can insert own orders" ON public.orders
  FOR INSERT WITH CHECK (auth.uid() = "userId");

CREATE POLICY "Users can update own orders" ON public.orders
  FOR UPDATE USING (auth.uid() = "userId");

CREATE INDEX IF NOT EXISTS idx_orders_user_id ON public.orders("userId");
CREATE INDEX IF NOT EXISTS idx_orders_restaurant_id ON public.orders("restaurantId");
CREATE INDEX IF NOT EXISTS idx_orders_status ON public.orders(status);
CREATE INDEX IF NOT EXISTS idx_orders_created_at ON public.orders(created_at DESC);

-- Order Items table
CREATE TABLE IF NOT EXISTS public."orderItems" (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "orderId" uuid NOT NULL REFERENCES public.orders(id) ON DELETE CASCADE,
  "menuItemId" uuid NOT NULL REFERENCES public."menuItems"(id) ON DELETE RESTRICT,
  quantity integer NOT NULL,
  "specialInstructions" text,
  "totalPrice" numeric NOT NULL,
  created_at timestamptz DEFAULT now()
);

ALTER TABLE public."orderItems" ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can view order items for own orders" ON public."orderItems"
  FOR SELECT USING (
    "orderId" IN (
      SELECT id FROM public.orders WHERE "userId" = auth.uid()
    )
  );

CREATE INDEX IF NOT EXISTS idx_order_items_order_id ON public."orderItems"("orderId");
CREATE INDEX IF NOT EXISTS idx_order_items_menu_item_id ON public."orderItems"("menuItemId");

-- Order Item Customizations table
CREATE TABLE IF NOT EXISTS public."orderItemCustomizations" (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "orderItemId" uuid NOT NULL REFERENCES public."orderItems"(id) ON DELETE CASCADE,
  "groupId" text,
  "groupName" text,
  "optionId" text,
  "optionName" text,
  price numeric,
  created_at timestamptz DEFAULT now()
);

ALTER TABLE public."orderItemCustomizations" ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can view customizations for own orders" ON public."orderItemCustomizations"
  FOR SELECT USING (
    "orderItemId" IN (
      SELECT id FROM public."orderItems" WHERE "orderId" IN (
        SELECT id FROM public.orders WHERE "userId" = auth.uid()
      )
    )
  );

CREATE INDEX IF NOT EXISTS idx_order_item_customizations_order_item_id ON public."orderItemCustomizations"("orderItemId");

-- Order Status History table
CREATE TABLE IF NOT EXISTS public."orderStatusHistory" (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "orderId" uuid NOT NULL REFERENCES public.orders(id) ON DELETE CASCADE,
  status text NOT NULL,
  message text,
  "timestamp" timestamptz DEFAULT now(),
  created_at timestamptz DEFAULT now()
);

ALTER TABLE public."orderStatusHistory" ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can view status history for own orders" ON public."orderStatusHistory"
  FOR SELECT USING (
    "orderId" IN (
      SELECT id FROM public.orders WHERE "userId" = auth.uid()
    )
  );

CREATE INDEX IF NOT EXISTS idx_order_status_history_order_id ON public."orderStatusHistory"("orderId");
CREATE INDEX IF NOT EXISTS idx_order_status_history_timestamp ON public."orderStatusHistory"("timestamp" DESC);

-- Delivery Partners table
CREATE TABLE IF NOT EXISTS public."deliveryPartners" (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  name text NOT NULL,
  phone text,
  avatar text,
  latitude numeric,
  longitude numeric,
  rating numeric,
  "vehicleType" text,
  "vehiclePlate" text,
  created_at timestamptz DEFAULT now(),
  updated_at timestamptz DEFAULT now()
