ALTER TABLE public."deliveryPartners" ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Anyone can view delivery partners" ON public."deliveryPartners"
  FOR SELECT USING (true);

CREATE INDEX IF NOT EXISTS idx_delivery_partners_rating ON public."deliveryPartners"(rating DESC);

-- Promo Codes table
CREATE TABLE IF NOT EXISTS public."promoCodes" (
