ALTER TABLE public."promoCodes" ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Anyone can view valid promo codes" ON public."promoCodes"
  FOR SELECT USING ("isValid" = true AND ("expiresAt" IS NULL OR "expiresAt" > now()));

CREATE INDEX IF NOT EXISTS idx_promo_codes_code ON public."promoCodes"(code);
CREATE INDEX IF NOT EXISTS idx_promo_codes_is_valid ON public."promoCodes"("isValid");

-- Reviews table
CREATE TABLE IF NOT EXISTS public.reviews (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "userId" uuid NOT NULL REFERENCES public.users(id) ON DELETE CASCADE,
  "userName" text,
  "userAvatar" text,
  "restaurantId" uuid NOT NULL REFERENCES public.restaurants(id) ON DELETE CASCADE,
  "orderId" uuid REFERENCES public.orders(id) ON DELETE SET NULL,
  rating integer NOT NULL,
  text text,
  "imageUrls" text[],
  created_at timestamptz DEFAULT now(),
  updated_at timestamptz DEFAULT now()
