CREATE INDEX IF NOT EXISTS idx_user_favorites_restaurant_id ON public."userFavorites"("restaurantId");

-- Handle new user creation from auth.users
CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
  INSERT INTO public.users (id, email, name, phone, avatar, "defaultAddressId", "walletBalance", "referralCode", created_at, updated_at)
  VALUES (
    NEW.id,
    NEW.email,
    NEW.raw_user_meta_data ->> 'name',
    NEW.raw_user_meta_data ->> 'phone',
    NEW.raw_user_meta_data ->> 'avatar',
    NEW.raw_user_meta_data ->> 'defaultAddressId',
    COALESCE((NEW.raw_user_meta_data ->> 'walletBalance')::numeric, 0),
    NEW.raw_user_meta_data ->> 'referralCode',
    now(),
    now()
  )
  ON CONFLICT (id) DO NOTHING;
  RETURN NEW;
END; $$;

DROP TRIGGER IF EXISTS on_auth_user_created ON auth.users;
CREATE TRIGGER on_auth_user_created AFTER INSERT ON auth.users FOR EACH ROW EXECUTE FUNCTION public.handle_new_user();

